package com.yottastudios.ns.collabspace.subscription.manager;

import com.baomidou.mybatisplus.core.metadata.IPage;
import com.yottastudios.ns.collabspace.subscription.vo.SubscriptionCheckVo;
import com.yottastudios.ns.collabspace.subscription.vo.SubscriptionListVo;

import java.util.List;

public interface DocSubscriptionManager {

    /**
     * 订阅单个文档节点（幂等：已订阅则跳过）
     */
    void subscribe(Long userId, Long spaceNodeId);

    /**
     * 批量订阅文档节点（自动过滤文件夹和已订阅节点）
     */
    void batchSubscribe(Long userId, List<Long> spaceNodeIds);

    /**
     * 取消订阅单个文档节点
     */
    void unsubscribe(Long userId, Long spaceNodeId);

    /**
     * 批量取消订阅文档节点
     */
    void batchUnsubscribe(Long userId, List<Long> spaceNodeIds);

    /**
     * 分页查询用户订阅列表
     */
    IPage<SubscriptionListVo> listSubscriptions(Long userId, int pageNum, int pageSize);

    /**
     * 批量检查用户对指定节点的订阅状态
     */
    SubscriptionCheckVo checkSubscriptions(Long userId, List<Long> spaceNodeIds);

    /**
     * 今日不再提示确认（Redis 存储，当日有效）
     */
    void dismissConfirmToday(Long userId);

    /**
     * 查询当日是否已勾选"不再提示"
     */
    boolean isDismissedToday(Long userId);
}

package com.yottastudios.ns.collabspace.subscription.manager.impl;

import com.baomidou.mybatisplus.core.metadata.IPage;
import com.baomidou.mybatisplus.extension.plugins.pagination.Page;
import com.yottastudios.ns.collabspace.core.exception.BusinessException;
import com.yottastudios.ns.collabspace.core.util.ExceptionUtil;
import com.yottastudios.ns.collabspace.subscription.entity.DocSubscriptionEntity;
import com.yottastudios.ns.collabspace.subscription.manager.DocSubscriptionManager;
import com.yottastudios.ns.collabspace.subscription.service.IDocSubscriptionService;
import com.yottastudios.ns.collabspace.subscription.vo.SubscriptionCheckVo;
import com.yottastudios.ns.collabspace.subscription.vo.SubscriptionListVo;
import com.yottastudios.ns.collabspace.workspace.entity.SpaceNodeEntity;
import com.yottastudios.ns.collabspace.workspace.enums.SpaceNodeException;
import com.yottastudios.ns.collabspace.workspace.enums.SpaceNodeTypeEnum;
import com.yottastudios.ns.collabspace.workspace.service.ISpaceNodeService;
import jakarta.annotation.Resource;
import lombok.extern.slf4j.Slf4j;
import org.springframework.data.redis.core.StringRedisTemplate;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.Duration;
import java.time.LocalDate;
import java.time.LocalDateTime;
import java.time.LocalTime;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.Set;
import java.util.stream.Collectors;

@Slf4j
@Service
public class DocSubscriptionManagerImpl implements DocSubscriptionManager {

    private static final String LOG_PREFIX = "[2424-订阅]";
    private static final String DISMISS_CONFIRM_KEY_PREFIX = "subscription:dismiss_confirm:";

    @Resource
    private IDocSubscriptionService docSubscriptionService;

    @Resource
    private ISpaceNodeService spaceNodeService;

    @Resource
    private StringRedisTemplate stringRedisTemplate;

    @Override
    @Transactional
    public void subscribe(Long userId, Long spaceNodeId) {
        // 校验节点存在且非文件夹
        SpaceNodeEntity node = spaceNodeService.getById(spaceNodeId);
        ExceptionUtil.isNotNull(node, SpaceNodeException.NOT_EXIST);
        if (SpaceNodeTypeEnum.FOLDER.getValue().equals(node.getType())) {
            throw new BusinessException(SpaceNodeException.INVALID_TYPE);
        }

        // 幂等：已订阅则跳过
        DocSubscriptionEntity existing = docSubscriptionService.getByUserIdAndSpaceNodeId(userId, spaceNodeId);
        if (existing != null) {
            log.info("{} 已订阅，跳过 userId={} spaceNodeId={}", LOG_PREFIX, userId, spaceNodeId);
            return;
        }

        DocSubscriptionEntity entity = DocSubscriptionEntity.builder()
                .userId(userId)
                .spaceNodeId(spaceNodeId)
                .spaceId(node.getSpaceId())
                .build();
        docSubscriptionService.save(entity);
        log.info("{} 订阅成功 userId={} spaceNodeId={} spaceId={}", LOG_PREFIX, userId, spaceNodeId, node.getSpaceId());
    }

    @Override
    @Transactional
    public void batchSubscribe(Long userId, List<Long> spaceNodeIds) {
        // 过滤文件夹节点
        List<Long> validIds = filterFolders(spaceNodeIds);
        if (validIds.isEmpty()) {
            log.info("{} 批量订阅：全部为文件夹或节点不存在，跳过 userId={}", LOG_PREFIX, userId);
            return;
        }

        // 排除已订阅的节点
        List<DocSubscriptionEntity> existingList = docSubscriptionService.listByUserIdAndSpaceNodeIds(userId, validIds);
        Set<Long> alreadySubscribed = existingList.stream()
                .map(DocSubscriptionEntity::getSpaceNodeId)
                .collect(Collectors.toSet());

        // 加载节点信息（用于获取 spaceId）
        List<SpaceNodeEntity> nodes = spaceNodeService.listByIds(validIds);
        Map<Long, SpaceNodeEntity> nodeMap = nodes.stream()
                .collect(Collectors.toMap(SpaceNodeEntity::getId, n -> n));

        List<DocSubscriptionEntity> toSave = new ArrayList<>();
        for (Long nodeId : validIds) {
            if (alreadySubscribed.contains(nodeId)) {
                continue;
            }
            SpaceNodeEntity node = nodeMap.get(nodeId);
            if (node == null) {
                continue;
            }
            toSave.add(DocSubscriptionEntity.builder()
                    .userId(userId)
                    .spaceNodeId(nodeId)
                    .spaceId(node.getSpaceId())
                    .build());
        }

        if (!toSave.isEmpty()) {
            docSubscriptionService.saveBatch(toSave);
            log.info("{} 批量订阅成功 userId={} count={}", LOG_PREFIX, userId, toSave.size());
        } else {
            log.info("{} 批量订阅：无新增记录 userId={}", LOG_PREFIX, userId);
        }
    }

    @Override
    @Transactional
    public void unsubscribe(Long userId, Long spaceNodeId) {
        DocSubscriptionEntity existing = docSubscriptionService.getByUserIdAndSpaceNodeId(userId, spaceNodeId);
        if (existing == null) {
            log.info("{} 未订阅，跳过取消 userId={} spaceNodeId={}", LOG_PREFIX, userId, spaceNodeId);
            return;
        }
        docSubscriptionService.removeById(existing);
        log.info("{} 取消订阅成功 userId={} spaceNodeId={}", LOG_PREFIX, userId, spaceNodeId);
    }

    @Override
    @Transactional
    public void batchUnsubscribe(Long userId, List<Long> spaceNodeIds) {
        List<DocSubscriptionEntity> existingList = docSubscriptionService.listByUserIdAndSpaceNodeIds(userId, spaceNodeIds);
        if (existingList.isEmpty()) {
            log.info("{} 批量取消订阅：无匹配记录 userId={}", LOG_PREFIX, userId);
            return;
        }
        List<Long> ids = existingList.stream().map(DocSubscriptionEntity::getId).collect(Collectors.toList());
        docSubscriptionService.removeByIds(ids);
        log.info("{} 批量取消订阅成功 userId={} count={}", LOG_PREFIX, userId, ids.size());
    }

    @Override
    public IPage<SubscriptionListVo> listSubscriptions(Long userId, int pageNum, int pageSize) {
        IPage<DocSubscriptionEntity> entityPage = docSubscriptionService.pageByUserId(userId, pageNum, pageSize);

        List<Long> nodeIds = entityPage.getRecords().stream()
                .map(DocSubscriptionEntity::getSpaceNodeId)
                .collect(Collectors.toList());

        // 批量加载节点信息
        Map<Long, SpaceNodeEntity> nodeMap = new HashMap<>();
        if (!nodeIds.isEmpty()) {
            List<SpaceNodeEntity> nodes = spaceNodeService.listByIds(nodeIds);
            nodeMap = nodes.stream().collect(Collectors.toMap(SpaceNodeEntity::getId, n -> n));
        }

        Map<Long, SpaceNodeEntity> finalNodeMap = nodeMap;
        List<SubscriptionListVo> voList = entityPage.getRecords().stream()
                .map(entity -> {
                    SpaceNodeEntity node = finalNodeMap.get(entity.getSpaceNodeId());
                    // 节点已删除时展示占位名称
                    String name = node != null ? node.getName() : "[已删除]";
                    String icon = node != null ? node.getIcon() : null;
                    Integer type = node != null ? node.getType() : null;
                    LocalDateTime updatedAt = node != null ? node.getUpdatedAt() : null;
                    return SubscriptionListVo.builder()
                            .id(entity.getId())
                            .spaceNodeId(entity.getSpaceNodeId())
                            .name(name)
                            .icon(icon)
                            .type(type)
                            .subscribedAt(entity.getCreatedAt())
                            .updatedAt(updatedAt)
                            .build();
                })
                .collect(Collectors.toList());

        // 构造结果分页对象，复用原分页元数据
        IPage<SubscriptionListVo> resultPage = new Page<>(entityPage.getCurrent(), entityPage.getSize(), entityPage.getTotal());
        resultPage.setRecords(voList);
        return resultPage;
    }

    @Override
    public SubscriptionCheckVo checkSubscriptions(Long userId, List<Long> spaceNodeIds) {
        List<DocSubscriptionEntity> existingList = docSubscriptionService.listByUserIdAndSpaceNodeIds(userId, spaceNodeIds);
        Set<Long> subscribedIds = existingList.stream()
                .map(DocSubscriptionEntity::getSpaceNodeId)
                .collect(Collectors.toSet());

        // 用 String key 避免前端 Long 精度丢失
        Map<String, Boolean> result = new HashMap<>(spaceNodeIds.size());
        for (Long nodeId : spaceNodeIds) {
            result.put(String.valueOf(nodeId), subscribedIds.contains(nodeId));
        }
        return SubscriptionCheckVo.builder().subscribed(result).build();
    }

    @Override
    public void dismissConfirmToday(Long userId) {
        String key = DISMISS_CONFIRM_KEY_PREFIX + userId;
        // TTL 到当日 23:59:59
        LocalDateTime endOfDay = LocalDateTime.of(LocalDate.now(), LocalTime.MAX);
        Duration ttl = Duration.between(LocalDateTime.now(), endOfDay);
        stringRedisTemplate.opsForValue().set(key, "1", ttl);
        log.info("{} 今日不再提示 userId={}", LOG_PREFIX, userId);
    }

    @Override
    public boolean isDismissedToday(Long userId) {
        String key = DISMISS_CONFIRM_KEY_PREFIX + userId;
        return Boolean.TRUE.equals(stringRedisTemplate.hasKey(key));
    }

    /**
     * 过滤掉文件夹类型节点，返回可订阅的节点 ID 列表。
     * 不存在的节点也会被排除（listByIds 不返回不存在记录）。
     */
    private List<Long> filterFolders(List<Long> spaceNodeIds) {
        if (spaceNodeIds.isEmpty()) {
            return List.of();
        }
        List<SpaceNodeEntity> nodes = spaceNodeService.listByIds(spaceNodeIds);
        return nodes.stream()
                .filter(n -> !SpaceNodeTypeEnum.FOLDER.getValue().equals(n.getType()))
                .map(SpaceNodeEntity::getId)
                .collect(Collectors.toList());
    }
}

