import java.util.List;
import java.util.Map;

@Slf4j
@RestController
@Tag(name = "Subscription", description = "文档订阅管理")
@ApiResource(path = "/subscription")
public class SubscriptionController {

    @Resource
    private DocSubscriptionManager docSubscriptionManager;

    @PostResource(path = "/subscribe", requiredPermission = false)
    @Operation(summary = "订阅文档节点")
    public ResponseData<Void> subscribe(@RequestBody @Valid SubscribeRo ro) {
        Long userId = SessionContext.getUserId();
        docSubscriptionManager.subscribe(userId, ro.getSpaceNodeId());
        return ResponseData.success(null);
    }

    @PostResource(path = "/batchSubscribe", requiredPermission = false)
    @Operation(summary = "批量订阅文档节点")
    public ResponseData<Void> batchSubscribe(@RequestBody @Valid BatchSubscribeRo ro) {
        Long userId = SessionContext.getUserId();
        docSubscriptionManager.batchSubscribe(userId, ro.getSpaceNodeIds());
        return ResponseData.success(null);
    }

    @PostResource(path = "/unsubscribe", requiredPermission = false)
    @Operation(summary = "取消订阅文档节点")
    public ResponseData<Void> unsubscribe(@RequestBody @Valid SubscribeRo ro) {
        Long userId = SessionContext.getUserId();
        docSubscriptionManager.unsubscribe(userId, ro.getSpaceNodeId());
        return ResponseData.success(null);
    }

    @PostResource(path = "/batchUnsubscribe", requiredPermission = false)
    @Operation(summary = "批量取消订阅文档节点")
    public ResponseData<Void> batchUnsubscribe(@RequestBody @Valid BatchSubscribeRo ro) {
        Long userId = SessionContext.getUserId();
        docSubscriptionManager.batchUnsubscribe(userId, ro.getSpaceNodeIds());
        return ResponseData.success(null);
    }

    @PostResource(path = "/list", requiredPermission = false)
    @Operation(summary = "分页查询用户订阅列表")
    public ResponseData<IPage<SubscriptionListVo>> listSubscriptions(@RequestBody @Valid SubscriptionQueryRo ro) {
        Long userId = SessionContext.getUserId();
        IPage<SubscriptionListVo> result = docSubscriptionManager.listSubscriptions(userId, ro.getPageNum(), ro.getPageSize());
        return ResponseData.success(result);
    }

    @GetResource(path = "/check", requiredPermission = false)
    @Operation(summary = "批量查询文档节点订阅状态")
    public ResponseData<SubscriptionCheckVo> checkSubscriptions(@RequestParam List<Long> spaceNodeIds) {
        Long userId = SessionContext.getUserId();
        SubscriptionCheckVo result = docSubscriptionManager.checkSubscriptions(userId, spaceNodeIds);
        return ResponseData.success(result);
    }

    @PostResource(path = "/dismissConfirmToday", requiredPermission = false)
    @Operation(summary = "今日不再提示确认（当日有效）")
    public ResponseData<Void> dismissConfirmToday() {
        Long userId = SessionContext.getUserId();
        docSubscriptionManager.dismissConfirmToday(userId);
        return ResponseData.success(null);
    }

    @GetResource(path = "/dismissConfirmStatus", requiredPermission = false)
    @Operation(summary = "查询当日是否已勾选不再提示")
    public ResponseData<Map<String, Boolean>> dismissConfirmStatus() {
        Long userId = SessionContext.getUserId();
        boolean dismissed = docSubscriptionManager.isDismissedToday(userId);
        return ResponseData.success(Map.of("dismissed", dismissed));
    }
}

